section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "daily-marketing-standup-checklist-output",
  "required": [
    "date",
    "owner",
    "one_thing_focus",
    "content_queue_status",
    "social_pulse",
    "anomalies",
    "forbidden_seen"
  ],
  "properties": {
    "date": {
      "description": "Standup date."
    },
    "owner": {
      "description": "Owner name."
    },
    "one_thing_focus": {
      "description": "\u226415 words."
    },
    "content_queue_status": {
      "description": "{posts_ready, posts_blocked, blockers}."
    },
    "social_pulse": {
      "description": "Per-channel impressions/clicks/anomalies."
    },
    "anomalies": {
      "description": "{metric, delta_pct, hypothesis, owner}."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
